{"content": "#!/usr/bin/env python3
"""Fix remaining targetKeyword issues in content/es.json."""

import json

ES_PATH = "/root/nexa-paraguay/content/es.json"

with open(ES_PATH, "r") as f:
    es_content = f.read()

try:
    es_data = json.loads(es_content)
except json.JSONDecodeError as e:
    print(f"ERROR: es.json is invalid JSON: {e}")
    exit(1)

# === Fix 1: Add targetKeyword to privacyPage.seo ===
if "privacyPage" in es_data and "seo" in es_data["privacyPage"]:
    seo = es_data["privacyPage"]["seo"]
    if "targetKeyword" not in seo:
        new_seo = {}
        for k, v in seo.items():
            new_seo[k] = v
            if k == "description":
                new_seo["targetKeyword"] = "política privacidad Nexa Paraguay"
        seo.clear()
        seo.update(new_seo)
        print("OK: privacyPage.seo -> targetKeyword=\"política privacidad Nexa Paraguay\"")
    else:
        print("SKIP: privacyPage.seo already has targetKeyword")
else:
    print("ERROR: privacyPage.seo not found in es.json")

# === Fix 2: Add SEO section to feedback (it's under home.feedback currently without seo) ===
# The feedback page needs its own SEO section. Looking at home.feedback, it's
# just a feedback form section. We need to add a feedbackPage.seo section.
# Actually, looking at the es.json structure more carefully - feedback is nested
# inside "home" and the page nexa-pages/feedback.json references content keys 
# like "feedback.hero" and "feedback" (both under home.feedback).
# 
# The task says to add to "each page's seo section" - for feedback, there isn't
# one. Let me check if there's a "feedbackPage" key.

if "feedbackPage" not in es_data:
    print("INFO: feedbackPage section doesn't exist in es.json - could add one")
    print("INFO: feedback page content is nested under home.feedback")

    # The task says to add targetKeyword to matching content in es.json under each page's seo section.
    # For pages that don't have an SEO section, we should create one.
    # Let me check if there's a placeholder or if we should add it somewhere logical.

# === Fix 3: Check all the pages that were already processed ===
# Let's verify which ones now have targetKeyword
pages_with = []
pages_without = []
for key, val in es_data.items():
    if isinstance(val, dict):
        if "seo" in val and "targetKeyword" in val["seo"]:
            pages_with.append(key)
        elif "seo" in val:
            pages_without.append(key)
    if isinstance(val, dict):
        for k2, v2 in val.items():
            if isinstance(v2, dict) and "seo" in v2:
                if "targetKeyword" in v2["seo"]:
                    pages_with.append(f"{key}.{k2}")
                else:
                    pages_without.append(f"{key}.{k2}")

print(f"\nSEO sections WITH targetKeyword: {len(pages_with)}")
print(f"SEO sections WITHOUT targetKeyword: {len(pages_without)}")
for p in pages_without:
    print(f"  MISSING: {p}")

# Write back the changes
indent = None
for line in es_content.split("\n"):
    if line.startswith("  \"") and not line.startswith("    \""):
        indent = 2
        break
    if line.startswith("    \"") and not line.startswith("      \""):
        indent = 4
        break
if indent is None:
    indent = 2

new_content = json.dumps(es_data, indent=indent, ensure_ascii=False) + "\n"

try:
    json.loads(new_content)
    with open(ES_PATH, "w") as f:
        f.write(new_content)
    print(f"\nOK: es.json updated and valid JSON")
except json.JSONDecodeError as e:
    print(f"\nERROR: resulting JSON invalid: {e}")
